spec:
// Deployment/runtime contract for nginx-based web serving
// Files: nginx/nginx.conf, nginx/security-headers.conf, nginx/ssl.conf, Dockerfile

// Docker runtime stage now copies the entire nginx directory:
// COPY nginx/ /etc/nginx/

// Active HTTP server (`/etc/nginx/nginx.conf`):
// - worker_processes auto
// - worker_connections 1024
// - server_tokens off
// - gzip enabled for text/css/js/json/xml/svg assets
// - GET /health returns 200 OK with text/plain
// - SPA fallback: try_files $uri $uri/ /index.html
// - /index.html and /metadata.json are served with no-cache headers
// - Hashed Expo assets under `/_expo/static/` are served with `Cache-Control: public, max-age=31536000, immutable`

// Shared headers include (`/etc/nginx/security-headers.conf`):
// - X-Content-Type-Options: nosniff
// - X-Frame-Options: DENY
// - X-XSS-Protection: 1;mode=block
// - Referrer-Policy: strict-origin-when-cross-origin
// - Content-Security-Policy allows self, Supabase (`https://*.supabase.co`, `https://*.supabase.in`, matching wss://), and Google OAuth endpoints (`accounts.google.com`, `oauth2.googleapis.com`, `www.googleapis.com`, `apis.google.com`)

// HTTPS template (`/etc/nginx/ssl.conf`):
// - dormant 443 server block with placeholder cert paths under /etc/nginx/certs
// - mirrors the same SPA fallback, health check, cache policy, and security headers
// - intended to be enabled only after certificates are provisioned
